package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

class CSVFormatTest {

    @Test
    void testWithQuote_char() {
        // Arrange
        CSVFormat original = CSVFormat.DEFAULT;
        char quoteChar = '\'';

        // Act
        CSVFormat result = original.withQuote(quoteChar);

        // Assert
        assertNotNull(result);
        assertNotSame(original, result);
        assertEquals(Character.valueOf(quoteChar), result.getQuoteCharacter());
    }

    @Test
    void testWithQuote_nullCharacter() {
        // Arrange
        CSVFormat original = CSVFormat.DEFAULT;
        Character quoteChar = null;

        // Act
        CSVFormat result = original.withQuote(quoteChar);

        // Assert
        assertNotNull(result);
        assertNotSame(original, result);
        assertNull(result.getQuoteCharacter());
    }

    @Test
    void testWithQuote_sameQuoteCharacterReturnsSameInstance() {
        // Arrange
        CSVFormat original = CSVFormat.DEFAULT;
        Character quoteChar = original.getQuoteCharacter();

        // Act
        CSVFormat result = original.withQuote(quoteChar);

        // Assert
        assertSame(original, result);
    }
}
